import pyotp
import qrcode
import os
from flask import Flask, request, jsonify

app = Flask(__name__)

# Generate TOTP secret for a user
@app.route('/generate_secret/<username>', methods=['GET'])
def generate_secret(username):
    totp = pyotp.TOTP(pyotp.random_base32())
    secret = totp.secret
    uri = totp.provisioning_uri(username, issuer_name='YourAppName')
    img = qrcode.make(uri)
    img_path = f"{username}_qrcode.png"
    img.save(img_path)
    return jsonify({'secret': secret, 'qrcode': img_path})

# Validate TOTP code
@app.route('/validate_totp', methods=['POST'])
def validate_totp():
    data = request.json
    secret = data['secret']
    user_input = data['code']
    totp = pyotp.TOTP(secret)
    is_valid = totp.verify(user_input)
    return jsonify({'valid': is_valid})

if __name__ == '__main__':
    app.run(debug=True)